queries.sparql:
PREFIX : <http://ambrosia.example.org/construction#>
PREFIX p: <http://ambrosia.example.org/construction/prop#>
SELECT ?proj ?dev ?con WHERE { ?dp a :Development_Project ; p:project_name ?proj ; p:hasReal_Estate_Developer ?d ; p:hasContractor ?c . ?d p:name ?dev . ?c p:name ?con }

PREFIX : <http://ambrosia.example.org/construction#>
PREFIX p: <http://ambrosia.example.org/construction/prop#>
SELECT ?proj ?ms ?dev ?con WHERE { ?dp a :Development_Project ; p:project_name ?proj ; p:hasReal_Estate_Developer ?d ; p:hasContractor ?c . ?pm a :Project_Milestone ; p:milestone_description ?ms ; p:hasDevelopment_Project ?dp . ?d p:name ?dev . ?c p:name ?con }

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/construction#>
PREFIX p: <http://ambrosia.example.org/construction/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?project_name ?milestone_description ?name WHERE {
  ?dp a :Development_Project .
  ?pm a :Project_Milestone .
  ?pm p:hasDevelopment_Project ?dp .
  ?oc a :Real_Estate_Developer .
  ?dp p:hasReal_Estate_Developer ?oc .
  ?dp p:project_name ?project_name .
  ?pm p:milestone_description ?milestone_description .
  ?oc p:name ?name .
} }
  component_2: { SELECT ?project_name ?milestone_description ?name WHERE {
  ?dp a :Development_Project .
  ?pm a :Project_Milestone .
  ?pm p:hasDevelopment_Project ?dp .
  ?oc a :Contractors .
  ?dp p:hasContractor ?oc .
  ?dp p:project_name ?project_name .
  ?pm p:milestone_description ?milestone_description .
  ?oc p:name ?name .
} }
  full: { SELECT ?proj ?ms ?dev ?con WHERE { ?dp a :Development_Project ; p:project_name ?proj ; p:hasReal_Estate_Developer ?d ; p:hasContractor ?c . ?pm a :Project_Milestone ; p:milestone_description ?ms ; p:hasDevelopment_Project ?dp . ?d p:name ?dev . ?c p:name ?con } }
}

